entries.text:
/* 简约气泡样式 mod by LAPLACE */
/* 一个朴素的动画效果 */
@316232045 eventIn {
  0% {
    opacity: 0;
    transform: translate3d(calc(var(--1px) * -10), 0, 0);
  }
  100% {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

/* 弹幕自定义样式 */
.event-type--message {
  --text: #ffffff;
  --bg: #53545c;
  --avatar-size: calc(var(--1px) * 32);
  display: flex;
  align-items: start;
  animation: eventIn .6s ease;
  will-change: transform;
}

/* 总督变量 */
.event-type--message.guard-level--1 {
  --bg: rgb(233, 88, 110);
}

/* 提督变量 */
.event-type--message.guard-level--2 {
  --bg: rgb(159, 102, 173);
}

/* 舰长变量 */
.event-type--message.guard-level--3 {
  --bg: rgb(87, 117, 227);
}

/* 主播变量 */
.event-type--message.user-type--streamer {
  --bg: rgb(180, 94, 54);
}

/* 隐藏不必要元素 */
.event-type--message .fans-medal,
.event-type--message .username,
.event-type--message .guard-badge {
  display: none;
}

/* 弹幕正文改为聊天泡泡样式 */
.event-type--message .message {
  position: relative;
  display: block;
  padding: calc(var(--1px) * 4) calc(var(--1px) * 12);
  color: var(--text);
  font-weight: bold;
  background-color: var(--bg);
  width: fit-content;
  border-radius: calc(var(--1px) * 18);
  border-top-left-radius: 0;
  filter: drop-shadow(0 2px 2px #000);
}

/* 为聊天泡泡增加尾巴 */
.event-type--message .message::before {
  content: "";
  display: inline-block;
  position: absolute;
  top: 0;
  left: -6px;
  border: 10px solid transparent;
  border-top: 10px solid var(--bg);
  transform: rotate(0);
}
